import React from "react";

const IntroSection = () => {
  return (
    <section style={{
      display: "flex",
      alignItems: "center",
      gap: "2rem",
      maxWidth: "900px",
      margin: "0 auto 4rem",
      flexWrap: "wrap"  // para que sea responsive
    }}>
      <div style={{ flex: 1, minWidth: "280px" }}>
        <h1 style={{ fontSize: "2.5rem", fontWeight: "900", marginBottom: "1rem", color: "#003E73" }}>
          Nice to meet you
        </h1>
        <p style={{ fontSize: "1.1rem", lineHeight: "1.6", color: "#003E73" }}>
          We're John and Jai, co-founders of Hydrant. Our journey started when both us (John, a scientist,
          and Jai, a finance consultant) were trying to solve the same problem on opposite sides of the US.
          After a friend connected us, the rest is history.
        </p>
      </div>

      <div style={{ flex: 1, minWidth: "280px", textAlign: "center" }}>
        <img
          src="../../assets/quien-contra-nosotros.jpg"
          alt="Cargando..."
          style={{ maxWidth: "100%", borderRadius: "1rem" }}
        />
      </div>
    </section>
  );
};

export default IntroSection;
